from agent import *from models.products import *import reimport simplejsondef strip_namespace(data):    tmp = data.content_file + ".tmp"    out = file(tmp, "w")    for line in file(data.content_file):        line = line.replace('<ns0', '<')        line = line.replace('ns0:', '')        line = line.replace(' xmlns', ' abcde=')        out.write(line + "\n")    out.close()    os.rename(tmp, data.content_file)def remove_emoji(string):    emoji_pattern = re.compile("["                               u"\U0001F600-\U0001F64F"  # emoticons                               u"\U0001F300-\U0001F5FF"  # symbols & pictographs                               u"\U0001F680-\U0001F6FF"  # transport & map symbols                               u"\U0001F1E0-\U0001F1FF"  # flags (iOS)                               u"\U00002500-\U00002BEF"  # chinese char                               u"\U00002702-\U000027B0"                               u"\U00002702-\U000027B0"                               u"\U000024C2-\U0001F251"                               u"\U0001f926-\U0001f937"                               u"\U00010000-\U0010ffff"                               u"\u2640-\u2642"                               u"\u2600-\u2B55"                               u"\u200d"                               u"\u23cf"                               u"\u23e9"                               u"\u231a"                               u"\ufe0f"  # dingbats                               u"\u3030"                               "]+", flags=re.UNICODE)    return emoji_pattern.sub(r'', string)def RequestRevs(offset):    url = 'https://www.pickr.com.au/wp-admin/admin-ajax.php'    payload = {        'action': 'pickrc_load_more_posts',        'nonce': '183d899848',        'offset': str(offset),        'per_page': '5',        'category_id': '157',        'tag_id': '0'    }    r = Request(url, data=payload, method='POST')    r.add_header('Accept-Encoding', 'deflate')    r.add_header('Cookie', '_color_system_schema=dark; pickrc-retina=true; icwp-wpsf-notbot=notbotZaltchaZexp-1778815071; icwp-wpsf-notbot=notbotZaltchaZexp-1778815773')    return rdef run(context, session):    session.browser.use_new_parser = True    session.sessionbreakers = [SessionBreak(max_requests=3000)]    session.do(RequestRevs(0), process_revlist, dict())def process_revlist(data, context, session):    strip_namespace(data)    try:        revs_json = simplejson.loads(data.content).get('data', {})    except:        revs_json = {}    new_data = data.parse_fragment(revs_json.get('html'))    revs = new_data.xpath('//article[contains(@id, "post-")]')    for rev in revs:        title = rev.xpath('.//h3[contains(@class, "title")]/text()').string()        ssid = rev.xpath('@id').string()        url = rev.xpath('a/@href').string()        session.queue(Request(url), process_review, dict(title=title, ssid=ssid, url=url))    offset = context.get('offset', 5) + 5    if revs_json.get('hasMore') is True:        session.do(RequestRevs(offset), process_revlist, dict(offset=offset))def process_review(data, context, session):    strip_namespace(data)    product = Product()    product.name = context['title'].split(' Reviewed: ')[0].split(' preview: ')[0].split(' reviewed: ')[0].split(' review: ')[0].replace(' reviewed', '').replace('Review: ', '').strip()    product.url = context['url']    product.category = 'Tech'    ssid = context['ssid']    if ssid:        product.ssid = ssid.replace('post-', '')    else:        product.ssid = product.url.split('/')[-2]    review = Review()    review.type = 'pro'    review.title = context['title']    review.url = product.url    review.ssid = product.ssid    date = data.xpath('//meta[@property="article:published_time"]/@content').string()    if date:        review.date = date.split('T')[0]    author = data.xpath('//meta[@name="author"]/@content').string()    author_url = data.xpath('//p[@class="author-name"]/a/@href').string()    if author and author_url:        author_ssid = author_url.split('/')[-2]        review.authors.append(Person(name=author, ssid=author_ssid, profile_url=author_url))    elif author:        review.authors.append(Person(name=author, ssid=author))    grade_overall = data.xpath('//div[@class="score"]/text()').string()    if not grade_overall:        grade_overall = data.xpath('//span[@class="score__number"]/text()').string()    if grade_overall and float(grade_overall) > 0:        review.grades.append(Grade(type='overall', value=float(grade_overall), best=5.0))    grades = data.xpath('//div[@class="lets-review-block__crit"]')    for grade in grades:        grade_name = grade.xpath('div[contains(@class, "title")]/text()').string()        grade_val = grade.xpath('@data-score').string()        if grade_name and grade_val and float(grade_val) > 0:            grade_val = float(grade_val) / 20            review.grades.append(Grade(name=grade_name, value=grade_val, best=5.0))    pros = data.xpath('//div[@class="lets-review-block__pros"]/div[contains(@class, "procon")]')    if not pros:        pros = data.xpath('//div[@class="review-list pros"]')    for pro in pros:        pro = pro.xpath('.//text()').string(multiple=True)        if pro:            pro = pro.strip(' +-*.:;•,–')            if len(pro) > 1:                review.add_property(type='pros', value=pro)    cons = data.xpath('//div[@class="lets-review-block__cons"]/div[contains(@class, "procon")]')    if not cons:        cons = data.xpath('//div[@class="review-list cons"]')    for con in cons:        con = con.xpath('.//text()').string(multiple=True)        if con:            con = con.strip(' +-*.:;•,–')            if len(con) > 1:                review.add_property(type='cons', value=con)    summary = data.xpath('//div[@class="post-hero-text"]/p//text()').string(multiple=True)    if summary:        review.add_property(type='summary', value=summary)    conclusion = data.xpath('//h2[regexp:test(., "Final thoughts", "i")]/following-sibling::p//text()').string(multiple=True)    if conclusion:        conclusion = remove_emoji(conclusion).strip()        review.add_property(type='conclusion', value=conclusion)    excerpt = data.xpath('//h2[regexp:test(., "Final thoughts", "i")]/preceding-sibling::p//text()').string(multiple=True)    if not excerpt:        excerpt = data.xpath('//main[contains(@class, "content")]/p//text()').string(multiple=True)    if excerpt:        excerpt = remove_emoji(re.sub(r'>a.href=.+>', '', excerpt)).strip()        if len(excerpt) > 2:            review.add_property(type='excerpt', value=excerpt)            product.reviews.append(review)            session.emit(product)